import { useCallback, useEffect, useState } from 'react';
import { connect } from 'react-redux';
import { first, take, tap } from 'rxjs/operators';
import { bcat, TheBlueprintsComponentsContex, TheBlueprintComponentsContext, useBlueprintComponentsContext } from '../../../../context/blueprintsComponents.context';
import { TheModulesContext } from '../../../../context/modules.context';
import { pat, TheProcessContext, TheProcessStepContext, useProcessContext } from '../../../../context/processStep.context';
import { resetSelectedProStep, setSelectedProStep, setMessageBar, setShowMenu, setCompanyProcesses, setSelectedProcess } from '../../../../reduxStore/actions/flowActions';
import { getProcessById, deleteProcessById } from '../../../../services/processes.service';
import { CLEAR_TO_SET_DATA, FORCED, } from '../../../../shared/utility';
import { Button, ModalR, PermissionWrapper, po } from '../../../common';
import ModulesOptionsModal from '../../ModulesComp/ModulesOptionsModal';
import ProcessOptionsModal from '../../BlueprintsComps/ProcessesTab/ProcessOptionsModal';
import WorkflowTemplatesModal from '../../BlueprintsComps/ProcessesTab/WorkflowTemplatesModal';
import ComponentsModal from '../ComponentsTab/ComponentsModal';
import cls from './ProcessInfo.module.scss';
import ProcessStepsChart from './ProcessStepsChart';
import StepModal from './StepModal';
import { isMobile } from 'react-device-detect';
import { store } from '../../../../reduxStore/store';
import { getAllComponentBlueprints } from '../../../../services/components.service';
import { useNavigate } from 'react-router-dom';

const ProcessInformationRaw = props => {
	const navigate = useNavigate();

	const { onClose, selectedProcess, onResetSelectedProStep, blueprints, allModules, companyProcesses, workflowTemplates } = props;
	const [, setFocusProcName] = useState(false);

	const [showStepModal, setShowStepModal] = useState(false);
	const [showProcessModal, setShowProcessModal] = useState(false);
	const [showDeleteModal, setShowDeleteModal] = useState(false);
	const [showComponentsModal, setShowComponentsModal] = useState(false);
	const [showComponentsWorkflowModal, setShowComponentsWorkflowModal] = useState(false);
	const [showProcessWorkflowModal, setShowProcessWorkflowModal] = useState(false);
	const [showModulesModal, setShowModulesModal] = useState(false);
	const [updateProcess, setUpdateProcess] = useState(false);
	const [, setBpComponentsContext] = useBlueprintComponentsContext();
	const [inProcContext, setInProcContext] = useProcessContext();
	const [loading, setLoading] = useState(false);
	const [showTemplates, setShowTemplates] = useState(false);
	document.title = selectedProcess.name;

	const onModalClose = () => {
		if (updateProcess == true) {
			getProcessById(selectedProcess.id).pipe(first()).subscribe({});
			getAllComponentBlueprints(CLEAR_TO_SET_DATA, FORCED).pipe(first()).subscribe({});
		}

		store.dispatch(setShowMenu(true));
		store.dispatch(setMessageBar({ show: false, message: '' }));
		navigate('/dashboard');
	};
	const onOpenAddNewStep = () => {
		if (selectedProcess?.name == '') {
			setFocusProcName(c => !c);
			return;
		}
		if (selectedProcess?.id?.length > 0) {
			onResetSelectedProStep();
			setShowStepModal(true);
		} else {
			setFocusProcName(c => !c);
		}
	};

	const onAddNewProcess = () => {
		setShowProcessModal(true);
	};
	const onAddNewComponent = () => {
		setBpComponentsContext({ type: bcat.resetsetSelectedBlueprintComponent });
		setShowComponentsModal(true);
	};
	const onAddNewModule = () => {
		setShowModulesModal(true);
	};

	const onDeleteProcess = () => {
		if (!selectedProcess?.id?.length > 0) {
			return;
		}
		setLoading(true);
		deleteProcessById(selectedProcess?.id)
			.pipe(first())
			.subscribe({
				next: _data => {
					setShowDeleteModal(false);
					setLoading(false);
					setUpdateProcess(true);
					onModalClose();
				},
				error: _error => {
					setLoading(false);
					setShowDeleteModal(false);
				},
			});
	};
	useEffect(() => {
		if (selectedProcess?.name !== '' && (selectedProcess?.steps?.length > 0 || selectedProcess?.steps > 0 || inProcContext?.steps?.length > 0)) {
			if (allModules.filter(mod => mod.procedure.id === selectedProcess?.id)?.length === 0) {
				store.dispatch(setMessageBar({ show: true, message: 'You can now create modules. Modules are pages where your users can interact with the workflows and components you created. This is where transactions are created.' }));
			} else if (allModules.filter(mod => mod.procedure.id === selectedProcess?.id)?.length > 0 && selectedProcess?.steps?.length == 1) {
				store.dispatch(setMessageBar({ show: true, message: 'To edit your step, click the box of your target step. The edit step modal will appear. There you can edit and update your step.' }));
			}
		} else if (selectedProcess?.name !== '' && blueprints?.length > 0) {

			if (selectedProcess.created == true) {
				store.dispatch(
					setMessageBar({
						show: true,
						message: `You have just created ${selectedProcess?.name} workflow and modules. Kindly configure Modules. After doing this you can now use your workflow module.`,
					})
				);
			} else {
				store.dispatch(
					setMessageBar({
						show: true,
						message: 'Add steps to define workflow. In these steps, you can attach components that will serve as input and output for workflow. Click the Step button above.',
						action: () => {
							setInProcContext({ type: pat.addNewStep, value: selectedProcess.id });
							setShowStepModal(true);
						},
					})
				);
			}

		} else if (selectedProcess?.name === '' && workflowTemplates.length == 0 && blueprints?.length > 0) {
			store.dispatch(setMessageBar({ show: true, message: 'To begin building your Workflow, click the Edit button, enter name, description and save. You can also build components before creating your workflow.' }));
			setShowProcessModal(true);
		} else if (selectedProcess?.name === '' && workflowTemplates.length > 0 && blueprints?.length > 0) {
			setShowTemplates(true);
		} else if (blueprints?.length === 0 && selectedProcess?.name === '') {
			store.dispatch(
				setMessageBar({
					show: true,
					message: 'To begin buiding your Workflow, start by creating blueprint components. Components are field data that you can use to gather information on your steps',
					action: () => {
						setShowComponentsModal(true);
					},
				})
			);
		}
	}, [allModules, selectedProcess, blueprints]);

	return (
		<>
			<div className={cls.host}>
				<div style={isMobile ? { padding: '0 0 0 10px', position: 'fixed', bottom: '0' } : { padding: '0 0 0 10px' }}>
					<Button title={'Close'} clicked={() => onModalClose()} />
				</div>
				<div style={isMobile ? { display: 'flex' } : { position: 'fixed', right: '0', top: '0', display: 'flex', flexDirection: 'row', padding: '0 10px 0 0px' }}>
					<AddNewProcess onAddNewProcess={onAddNewProcess} />
					{selectedProcess?.name !== '' && inProcContext?.steps?.length > 0 && selectedProcess?.name !== '' && <AddNewModule onAddNewModule={onAddNewModule} />}
					{selectedProcess?.name !== '' && blueprints?.length > 0 && <AddNewStepButton processID={selectedProcess.id} selectedProcessName={selectedProcess.name} onOpenAddNewStep={onOpenAddNewStep} />}
					<AddNewComponent onAddNewComponent={onAddNewComponent} />

					{allModules.filter(mod => mod.procedure.id === selectedProcess?.id).length === 0 && selectedProcess?.name !== '' && (
						<PermissionWrapper permissions={[po.blueprints.process.delete]}>
							<Button light title={'Delete'} clicked={() => setShowDeleteModal(true)} />
							<span className={cls.control} />
						</PermissionWrapper>
					)}
				</div>
				{blueprints?.length > 0 && (
					<div className={cls.processNameContainer} />


				)}
				<ProcessStepsChart onEditStep={() => setShowStepModal(true)} onEditStepEnded={showStepModal} />
			</div>


			<StepModal
				visible={showStepModal}
				onClose={value => {
					setUpdateProcess(value);
					onResetSelectedProStep();
					setShowStepModal(false);
				}}
			/>


			<ModalR isOpen={showDeleteModal} onClose={() => setShowDeleteModal(false)} backdropColor={true} blured={true} shadowedContainerStyle={{ width: isMobile ? '100%' : '30%', height: '160px' }}>
				<div className={cls.deleteModalContainer}>
					<div className={cls.deleteModalTextContainer}>
						<p className={cls.deteteModalText}>{'Are you sure you want to delete this workflow?'}</p>
					</div>
					<div className={cls.deleteModalButtonContainer}>
						<Button title={'Delete'} clicked={() => onDeleteProcess()} loading={loading} />
						<Button light title={'No, Go back'} clicked={() => setShowDeleteModal(false)} />
					</div>
				</div>
			</ModalR>



			<ComponentsModal
				visible={showComponentsModal}
				onClose={value => {
					setUpdateProcess(value);
					setShowComponentsModal(false);
				}}
				onUpdate={value => {
					store.dispatch(
						setCompanyProcesses(
							companyProcesses.filter(proc => proc.id !== selectedProcess.id),
							1
						)
					);
				}}
			/>

			<ComponentsModal
				visible={showComponentsWorkflowModal}
				onClose={() => {
					store.dispatch(setMessageBar({ show: false, message: '' }));
					navigate('/')
				}}
				onUpdate={() => {
					store.dispatch(
						setCompanyProcesses(
							companyProcesses.filter(proc => proc.id !== selectedProcess.id),
							1
						)
					);
				}}
			/>

			<ModulesOptionsModal
				onClose={() => setShowModulesModal(false)}
				isOpen={showModulesModal}
				modalStyle={{ maxWidth: '500px' }}
				selectedProcessId={selectedProcess?.id} />


			<ProcessOptionsModal
				onCreate={() => {
					setShowProcessModal(false);
					setShowStepModal(true);
				}}
				onClose={() => setShowProcessModal(false)}
				isOpen={showProcessModal}
				modalStyle={{ maxWidth: '500px' }}
				selectedProcessId={selectedProcess?.id}
				selectedProcess={selectedProcess}
				shadowedContainerStyle={{ width: isMobile ? '100%' : '30%' }}
			/>

			<ProcessOptionsModal
				onCreate={() => {
					setShowProcessModal(false);
					setShowStepModal(true);
				}}
				onClose={() => navigate('/')}
				isOpen={showProcessWorkflowModal}
				modalStyle={{ maxWidth: '500px' }}
				selectedProcessId={selectedProcess?.id}
				selectedProcess={selectedProcess}
				shadowedContainerStyle={{ width: isMobile ? '100%' : '30%' }}
			/>


			<WorkflowTemplatesModal
				isOpen={showTemplates}
				onCreateBlank={() => {
					setShowProcessWorkflowModal(true);
					setShowTemplates(false);
				}}
				onClose={() => {
					setShowTemplates(false);
				}}
				gotoProcess={data => {
					setShowProcessModal(false);
					setShowTemplates(false);
					store.dispatch(setSelectedProcess({
						name: data?.name,
						description: data?.description,
						id: data.id,
						is_pinned: data?.is_pinned,
						user_id: data?.user_id,
						registered: true,
						type: data?.type,
						steps: data?.steps,
						created: true
					}));
				}}
				gotoComponents={() => {
					setShowProcessModal(false);
					setShowTemplates(false);
					setShowComponentsWorkflowModal(true);
				}}

				modalStyle={{ maxWidth: '500px' }}
				selectedProcessId={selectedProcess?.id}
				selectedProcess={selectedProcess}
				shadowedContainerStyle={{ width: isMobile ? '100%' : '50%', minWidth: '300px' }}
			/>

		</>
	);
};
const AddNewStepButton = props => {
	const { processID, selectedProcessName, onOpenAddNewStep } = props;
	const [, setInProcContext] = useProcessContext();
	const onAddNewStep = () => {
		if (selectedProcessName?.length > 0) {
			setInProcContext({ type: pat.addNewStep, value: processID });
		}
		onOpenAddNewStep && onOpenAddNewStep();
	};
	return <Button light title={'Step'} clicked={onAddNewStep} />;
};
const AddNewComponent = props => {
	const { onAddNewComponent } = props;

	return <Button light title={'Component'} clicked={onAddNewComponent} />;
};

const AddNewProcess = props => {
	const { onAddNewProcess } = props;

	return <Button light title={'Edit'} clicked={onAddNewProcess} />;
};
const AddNewModule = props => {
	const { onAddNewModule } = props;

	return <Button light title={'Module'} clicked={onAddNewModule} />;
};
const ProcessInformation = props => {
	return (
		<TheModulesContext>
			<TheProcessContext>
				<TheProcessStepContext>
					<TheBlueprintsComponentsContex>
						<TheBlueprintComponentsContext>
							<ProcessInformationRaw {...props} />
						</TheBlueprintComponentsContext>
					</TheBlueprintsComponentsContex>
				</TheProcessStepContext>
			</TheProcessContext>
		</TheModulesContext>
	);
};

const mapStateToProps = store => {
	const { selectedProcess, blueprints, allModules, companyProcesses, workflowTemplates } = store.flowReducer;
	return { selectedProcess, blueprints, allModules, companyProcesses, workflowTemplates };
};
const mapDispatchToProps = dispatch => {
	return {
		onSetSelectedProStep: selectedStep => dispatch(setSelectedProStep(selectedStep)),
		onResetSelectedProStep: () => dispatch(resetSelectedProStep()),
	};
};

export default connect(mapStateToProps, mapDispatchToProps)(ProcessInformation);
